// Server-side code
const WebSocket = require('ws');
const fs = require('fs');

const wss = new WebSocket.Server({ port: 8080 });

wss.on('connection', (ws) => {
  ws.on('message', (message) => {
    const filePath = message.filePath;
    const fileSize = message.fileSize;

    // Send file metadata to client
